// IS-A — inheritance, specialization
class Animal {
    void breathe() { System.out.println("Breathing"); }
    void eat()     { System.out.println("Eating"); }
}

class Dog extends Animal {  // Dog IS-A Animal — correct!
    void bark() { System.out.println("Woof!"); }
    // Dog can be used anywhere Animal is expected
}

// HAS-A — composition, using another object as a component
class Engine {
    void start() { System.out.println("Engine started"); }
    void stop()  { System.out.println("Engine stopped"); }
}

class Car {
    private Engine engine;  // Car HAS-A Engine — correct!
    private String model;

    Car(String model) {
        this.model = model;
        this.engine = new Engine();  // composition
    }

    void drive() {
        engine.start();  // delegates to Engine
        System.out.println(model + " is driving");
    }
}

// WRONG — Car IS-A Engine makes no sense
// class BadCar extends Engine { ... }
// badCar.pistonFire() — nonsensical on a Car!

// Favor composition over inheritance:
// Engine can be swapped at runtime (e.g., ElectricEngine)
class ElectricEngine extends Engine {
    @Override
    void start() { System.out.println("Electric motor humming"); }
}

// Car can use different engines without changing its class hierarchy
Car tesla = new Car("Tesla");
// tesla.engine = new ElectricEngine(); — flexibility through composition

// AGGREGATION — weak Has-a, objects exist independently
class Professor {
    String name;
    String expertise;
    Professor(String name, String expertise) {
        this.name = name;
        this.expertise = expertise;
    }
}

class University {
    private String name;
    private List<Professor> professors;  // holds references, didn't create them

    // Professor created OUTSIDE and passed IN — aggregation
    University(String name, List<Professor> professors) {
        this.name = name;
        this.professors = professors;
    }

    void addProfessor(Professor p) { professors.add(p); }
}

// Professor can exist without University:
Professor prof = new Professor("Dr. Smith", "CS");  // independent
University uni = new University("SJSU", new ArrayList<>());
uni.addProfessor(prof);
// uni = null;  // University gone, but prof still exists!

// COMPOSITION — strong Has-a, inner objects die with outer
class Room {
    String type;
    Room(String type) { this.type = type; }
}

class House {
    private String address;
    private List<Room> rooms;  // House OWNS these rooms

    // House CREATES rooms itself — composition
    House(String address) {
        this.address = address;
        this.rooms = new ArrayList<>();
        // Rooms don't exist until House creates them
        rooms.add(new Room("Living Room"));
        rooms.add(new Room("Bedroom"));
        rooms.add(new Room("Kitchen"));
    }
    // When House is garbage collected, Room objects have no other references
    // → Rooms are also collected — they 'die' with the House
}

// UML notation:
// Aggregation:  Library ◇──── Book  (hollow diamond)
// Composition:  House  ◆──── Room  (filled diamond)

