// VIOLATES OCP — must modify this class every time a new region is added
class TaxCalculator {
    public double calculate(double amount, String region) {
        if (region.equals("India")) {
            return amount * 1.18;  // 18% GST
        } else if (region.equals("US")) {
            return amount * 1.28;  // must OPEN this class to add US
        } else if (region.equals("UK")) {
            return amount * 1.20;  // must OPEN this class to add UK
        }
        return amount;  // adding Canada requires yet another modification!
    }
}

// FOLLOWS OCP — add new regions by adding new classes, zero changes to existing
interface TaxCalculator {
    double calculate(double amount);
}

// Existing implementations — NEVER modified after initial creation
class IndiaTax implements TaxCalculator {
    @Override
    public double calculate(double amount) {
        return amount * 1.18;  // closed for modification
    }
}

class USTax implements TaxCalculator {
    @Override
    public double calculate(double amount) {
        return amount * 1.28;  // closed for modification
    }
}

// Adding Canada — NEW class, ZERO changes to existing code
class CanadaTax implements TaxCalculator {
    @Override
    public double calculate(double amount) {
        return amount * 1.15;  // just add this class and it works
    }
}

// Client code — depends on abstraction, works with any implementation
class Invoice {
    private TaxCalculator taxCalculator;  // interface reference

    Invoice(TaxCalculator taxCalculator) {
        this.taxCalculator = taxCalculator;
    }

    public double getTotal(double baseAmount) {
        return taxCalculator.calculate(baseAmount);
    }
}

