// CLASSIC LSP VIOLATION — Square extending Rectangle
class Rectangle {
    protected int width;
    protected int height;

    public void setWidth(int width)   { this.width = width; }
    public void setHeight(int height) { this.height = height; }
    public int getArea()              { return width * height; }
}

class Square extends Rectangle {
    // Square must keep width == height, so override BOTH setters
    @Override
    public void setWidth(int width) {
        this.width = width;
        this.height = width;  // side effect! changes height too
    }

    @Override
    public void setHeight(int height) {
        this.height = height;
        this.width = height;  // side effect! changes width too
    }
}

// Code that works with Rectangle:
void testRectangle(Rectangle r) {
    r.setWidth(5);
    r.setHeight(10);
    // Any Rectangle should give area = 50
    assert r.getArea() == 50 : "Expected 50, got " + r.getArea();
}

testRectangle(new Rectangle());  // passes: 5 * 10 = 50
testRectangle(new Square());     // FAILS: Square made both 10, area = 100!
// LSP violated — Square cannot substitute for Rectangle correctly

// FIX — model correctly, don't force inheritance
interface Shape {
    int getArea();
}

class Rectangle implements Shape {
    private int width, height;
    Rectangle(int w, int h) { this.width = w; this.height = h; }
    @Override public int getArea() { return width * height; }
}

class Square implements Shape {
    private int side;
    Square(int side) { this.side = side; }
    @Override public int getArea() { return side * side; }
}
// Now both are Shapes but neither is forced to be the other

