// ABSTRACTION — the interface both sides depend on
interface RecommendationStrategy {
    void recommend();
}

// LOW-LEVEL — concrete details depend on abstraction
class TrendingRecommendation implements RecommendationStrategy {
    @Override public void recommend() { System.out.println("Trending now..."); }
}

class GenreRecommendation implements RecommendationStrategy {
    @Override public void recommend() { System.out.println("Based on genre..."); }
}

class RecentlyAddedRecommendation implements RecommendationStrategy {
    @Override public void recommend() { System.out.println("Recently added..."); }
}

// HIGH-LEVEL — depends only on abstraction, not on any specific impl
class Netflix {
    private RecommendationStrategy strategy;  // interface, not concrete class

    // Strategy INJECTED from outside — Netflix doesn't choose or create it
    Netflix(RecommendationStrategy strategy) {
        this.strategy = strategy;
    }

    public void showRecommendations() {
        strategy.recommend();  // works with ANY implementation
    }

    // Runtime swap — change behavior without changing Netflix
    public void setStrategy(RecommendationStrategy strategy) {
        this.strategy = strategy;
    }
}

