// Signal for ABSTRACT CLASS — shared state AND shared logic
abstract class BaseRecommendation {
    // SHARED STATE — all subclasses need this
    protected String userId;
    protected List<String> watchHistory;

    BaseRecommendation(String userId) {
        this.userId = userId;
        this.watchHistory = loadHistory(userId);
    }

    // SHARED LOGIC — common to all subclasses
    protected void logRecommendation(String item) {
        System.out.println("User " + userId + " shown: " + item);
    }

    private List<String> loadHistory(String userId) {
        return new ArrayList<>();  // fetch from DB
    }

    // ABSTRACT — each subclass has its own version
    abstract void recommend();
}

class TrendingRecommendationV2 extends BaseRecommendation {
    TrendingRecommendationV2(String userId) { super(userId); }

    @Override
    public void recommend() {
        // Can use userId, watchHistory from parent
        String item = "Trending Movie";
        logRecommendation(item);  // can use shared logic from parent
    }
}

