// All five SOLID principles working together in one example:
// Payment Processing System

// SRP — each class has one job
class OrderCalculator {      // calculates totals
    double calculate(Order order) { return order.price * order.quantity; }
}

class OrderValidator {       // validates orders
    boolean validate(Order order) { return order.price > 0 && order.quantity > 0; }
}

// OCP — add payment methods by adding classes, not modifying existing
interface PaymentProcessor {
    void process(double amount);
}

class CreditCardProcessor implements PaymentProcessor {
    @Override public void process(double amount) { System.out.println("CC: " + amount); }
}

class UPIProcessor implements PaymentProcessor {
    @Override public void process(double amount) { System.out.println("UPI: " + amount); }
}

// Adding new method — zero existing code modified:
class CryptoProcessor implements PaymentProcessor {
    @Override public void process(double amount) { System.out.println("Crypto: " + amount); }
}

// ISP — separate interfaces for different roles
interface Refundable { void refund(double amount); }
interface Reportable { String generateReport(); }
// CreditCardProcessor implements both, UPIProcessor implements only Refundable

// DIP — high-level OrderService depends on abstraction
class OrderService {
    private final OrderValidator validator;   // inject abstractions
    private final OrderCalculator calculator;
    private final PaymentProcessor payment;  // interface, not concrete

    OrderService(OrderValidator v, OrderCalculator c, PaymentProcessor p) {
        this.validator = v;
        this.calculator = c;
        this.payment = p;  // DI — any PaymentProcessor works
    }

    void processOrder(Order order) {
        if (!validator.validate(order)) throw new IllegalArgumentException("Invalid order");
        double total = calculator.calculate(order);
        payment.process(total);  // LSP — works with any PaymentProcessor subtype
    }
}

// LSP — any PaymentProcessor can substitute for any other without breaking OrderService

// CREATIONAL — control object creation
// Singleton: one instance only
// Factory: create objects without specifying concrete class
// Builder: step-by-step complex object construction

// STRUCTURAL — compose objects into larger structures
// Decorator: wrap object to add behavior
// Adapter:   make incompatible interfaces compatible
// Flyweight: share common data to save memory

// BEHAVIORAL — define object communication and responsibility
// Strategy:  family of interchangeable algorithms
// Observer:  notify many when one changes
// Chain:     pass request along handlers

// Quick pattern identification:
// "Ensure one instance globally"     → Singleton (Creational)
// "Create objects without new?"       → Factory (Creational)
// "Add features without subclassing?" → Decorator (Structural)
// "Incompatible interfaces?"          → Adapter (Structural)
// "Multiple algorithms, swap at runtime?" → Strategy (Behavioral)
// "One changes, many need to know?"   → Observer (Behavioral)
// "Memory optimization for many similar objects?" → Flyweight (Structural)

// Interview pattern:
// Always say: category → definition → problem it solves → example
// e.g. "Strategy is a Behavioral pattern that encapsulates interchangeable
//       algorithms. It solves the problem of rigid if-else chains when
//       behavior needs to vary. Example: Uber's ride matching — Nearest,
//       Priority, Airport strategies are interchangeable at runtime."

// PROBLEM — rigid if-else, violates OCP
class BadRideMatchingEngine {
    void matchRide(String userLocation, String strategy) {
        if (strategy.equals("nearest")) {
            System.out.println("Finding nearest driver to " + userLocation);
        } else if (strategy.equals("priority")) {
            System.out.println("Finding priority driver for " + userLocation);
        } else if (strategy.equals("airport")) {
            System.out.println("Finding airport driver for " + userLocation);
        }
        // Adding "surge" requires MODIFYING this class — OCP violation!
    }
}

// STRATEGY PATTERN — each algorithm in its own class

// Step 1: Strategy interface — the contract
interface RideMatchingStrategy {
    void match(String userLocation);
}

// Step 2: Concrete strategies — one class per algorithm
class NearestRideMatching implements RideMatchingStrategy {
    @Override
    public void match(String userLocation) {
        System.out.println("Finding nearest driver to " + userLocation);
    }
}

class PriorityRideMatching implements RideMatchingStrategy {
    @Override
    public void match(String userLocation) {
        System.out.println("Priority matching for " + userLocation);
    }
}

class AirportRideMatching implements RideMatchingStrategy {
    @Override
    public void match(String userLocation) {
        System.out.println("Airport pickup at " + userLocation);
    }
}

// Adding new strategy — ZERO changes to existing code (OCP satisfied)
class SurgePricingRideMatching implements RideMatchingStrategy {
    @Override
    public void match(String userLocation) {
        System.out.println("Surge pricing match for " + userLocation);
    }
}

// Step 3: Context — uses strategy through interface
class StrategyEngine {
    private RideMatchingStrategy strategy;  // DIP: depends on interface

    // Strategy injected — engine doesn't choose the algorithm
    StrategyEngine(RideMatchingStrategy strategy) {
        this.strategy = strategy;
    }

    // Runtime swap — change algorithm without touching engine logic
    void setStrategy(RideMatchingStrategy strategy) {
        this.strategy = strategy;
    }

    void matchRide(String userLocation) {
        strategy.match(userLocation);  // delegates to whichever strategy is set
    }
}

// Usage:
StrategyEngine engine = new StrategyEngine(new NearestRideMatching());
engine.matchRide("San Jose");  // nearest

engine.setStrategy(new AirportRideMatching());
engine.matchRide("SJC Airport");  // airport — engine code unchanged

