// 2. SORTING STRATEGY
interface SortStrategy {
    void sort(int[] array);
}
class QuickSort  implements SortStrategy { public void sort(int[] a) { /* quicksort */ } }
class MergeSort  implements SortStrategy { public void sort(int[] a) { /* mergesort */ } }
class BubbleSort implements SortStrategy { public void sort(int[] a) { /* bubblesort */ } }

// Context selects strategy based on data size — runtime decision
class Sorter {
    SortStrategy strategy;
    Sorter(int dataSize) {
        // Choose algorithm based on context
        if (dataSize < 10)    strategy = new BubbleSort();
        else if (dataSize < 1000) strategy = new MergeSort();
        else                  strategy = new QuickSort();
    }
    void sort(int[] data) { strategy.sort(data); }
}

// 3. DISCOUNT STRATEGY
interface DiscountStrategy {
    double applyDiscount(double price);
}
class PercentageDiscount implements DiscountStrategy {
    double percent;
    PercentageDiscount(double percent) { this.percent = percent; }
    public double applyDiscount(double price) { return price * (1 - percent/100); }
}
class FlatDiscount implements DiscountStrategy {
    double flat;
    FlatDiscount(double flat) { this.flat = flat; }
    public double applyDiscount(double price) { return price - flat; }
}

