// Q: "Where would you use Strategy Pattern in an e-commerce system?"
// A: "I'd use it for the discount calculation engine — percentage off,
//     flat discount, buy-one-get-one. Each is a separate strategy.
//     The cart class holds a DiscountStrategy reference and applies
//     whichever is configured at checkout without knowing which one."

// Observer Pattern components:

// 1. OBSERVER INTERFACE — what all observers must implement
interface Subscriber {
    void update(String videoTitle);
}

// 2. CONCRETE OBSERVERS — different ways to handle notification
class EmailSubscriber implements Subscriber {
    private String username;
    EmailSubscriber(String username) { this.username = username; }

    @Override
    public void update(String videoTitle) {
        System.out.println("Email to " + username + ": New video — " + videoTitle);
    }
}

class AppSubscriber implements Subscriber {
    private String username;
    AppSubscriber(String username) { this.username = username; }

    @Override
    public void update(String videoTitle) {
        System.out.println("Push notification to " + username + ": " + videoTitle);
    }
}

// 3. SUBJECT INTERFACE
interface Channel {
    void subscribe(Subscriber subscriber);
    void unsubscribe(Subscriber subscriber);
    void notifySubscribers(String videoTitle);
}

// 4. CONCRETE SUBJECT — maintains subscriber list and triggers notifications
class YouTube implements Channel {
    private List<Subscriber> subscribers = new ArrayList<>();
    private String channelName;

    YouTube(String channelName) { this.channelName = channelName; }

    @Override
    public void subscribe(Subscriber subscriber) {
        subscribers.add(subscriber);
        System.out.println("New subscriber added to " + channelName);
    }

    @Override
    public void unsubscribe(Subscriber subscriber) {
        subscribers.remove(subscriber);
    }

    @Override
    public void notifySubscribers(String videoTitle) {
        // Channel doesn't know what TYPE each subscriber is
        // Just calls update() on all of them
        for (Subscriber subscriber : subscribers) {
            subscriber.update(videoTitle);
        }
    }

    // Event that triggers notification
    public void uploadVideo(String title) {
        System.out.println(channelName + " uploaded: " + title);
        notifySubscribers(title);  // automatically notifies all
    }
}

// Usage:
YouTube channel = new YouTube("TechWithHarsh");
Subscriber email = new EmailSubscriber("Harsh");
Subscriber app   = new AppSubscriber("Alex");

channel.subscribe(email);
channel.subscribe(app);
channel.uploadVideo("Design Patterns in Java");
// Output:
// TechWithHarsh uploaded: Design Patterns in Java
// Email to Harsh: New video — Design Patterns in Java
// Push notification to Alex: Design Patterns in Java

// PUSH MODEL — subject sends data to observers
interface PushSubscriber {
    void update(String videoTitle);  // data pushed by subject
}

// PULL MODEL — subject sends reference, observer pulls what it needs
interface PullSubscriber {
    void update(Channel channel);  // observer pulls data from channel
}

class SmartSubscriber implements PullSubscriber {
    @Override
    public void update(Channel channel) {
        // Pull only what this subscriber cares about
        String title    = channel.getLatestVideoTitle();
        int    duration = channel.getLatestVideoDuration();
        String category = channel.getLatestVideoCategory();
        // Can pull as much or as little as needed
        System.out.println("New " + duration + "min " + category + " video: " + title);
    }
}

// EXCEPTION HANDLING — naive implementation breaks notification chain
class NaiveYouTube {
    private List<Subscriber> subscribers = new ArrayList<>();

    void notifySubscribers(String title) {
        for (Subscriber s : subscribers) {
            s.update(title);  // if s throws exception, loop breaks!
            // subscribers after s never get notified
        }
    }
}

// ROBUST IMPLEMENTATION — isolate each subscriber
class RobustYouTube {
    private List<Subscriber> subscribers = new ArrayList<>();

    void notifySubscribers(String title) {
        for (Subscriber s : subscribers) {
            try {
                s.update(title);  // isolated — one failure doesn't affect others
            } catch (Exception e) {
                // Log the failure but CONTINUE to next subscriber
                System.err.println("Subscriber " + s + " failed: " + e.getMessage());
                // Don't rethrow — let other subscribers still get notified
            }
        }
    }
}

// Interview-level answer for exception question:
// "In the basic implementation, an exception in one subscriber
// breaks the notification loop — subsequent subscribers are skipped.
// The fix is to wrap each subscriber's update() call in a try-catch
// and log the error without rethrowing, so all subscribers are
// attempted regardless of individual failures. In production systems
// like Kafka or RabbitMQ, each consumer is independently managed
// so one failure is completely isolated from others."

// PROBLEM: Class explosion with inheritance
// PlainPizza, CheesePizza, MushroomPizza,
// CheeseMushroomPizza, CheeseOlivePizza...  — exponential!

// DECORATOR PATTERN SOLUTION

// Step 1: Component interface
interface Pizza {
    String description();
    double getCost();
}

// Step 2: Concrete Component — the base object
class PlainPizza implements Pizza {
    @Override
    public String description() { return "Plain Pizza"; }

    @Override
    public double getCost() { return 200.0; }
}

// Step 3: Abstract Decorator — implements same interface, holds component reference
abstract class PizzaDecorator implements Pizza {
    protected Pizza pizza;  // wrapped pizza (could be PlainPizza or another decorator)

    PizzaDecorator(Pizza pizza) {
        this.pizza = pizza;
    }
    // Subclasses must implement description() and getCost()
}

// Step 4: Concrete Decorators — each adds specific behavior
class ExtraCheese extends PizzaDecorator {
    ExtraCheese(Pizza pizza) { super(pizza); }

    @Override
    public String description() {
        return pizza.description() + " + Extra Cheese";  // delegate + extend
    }

    @Override
    public double getCost() {
        return pizza.getCost() + 40.0;  // delegate + add cost
    }
}

class Mushroom extends PizzaDecorator {
