// STRATEGY — behavior REPLACEMENT, one algorithm at a time
interface SortStrategy {
    void sort(int[] data);
}
class QuickSort  implements SortStrategy { public void sort(int[] d) { /* quicksort */ } }
class MergeSort  implements SortStrategy { public void sort(int[] d) { /* mergesort */ } }

class DataProcessor {
    private SortStrategy strategy;
    DataProcessor(SortStrategy strategy) { this.strategy = strategy; }
    // Uses ONE strategy at a time — REPLACE not stack
    void process(int[] data) { strategy.sort(data); }
    void setStrategy(SortStrategy s) { this.strategy = s; }  // swap strategy
}

// DECORATOR — behavior EXTENSION, multiple stack
interface Logger {
    void log(String message);
}

class ConsoleLogger implements Logger {
    @Override
    public void log(String message) {
        System.out.println(message);  // base behavior
    }
}

abstract class LoggerDecorator implements Logger {
    protected Logger logger;
    LoggerDecorator(Logger logger) { this.logger = logger; }
}

class TimestampDecorator extends LoggerDecorator {
    TimestampDecorator(Logger logger) { super(logger); }
    @Override
    public void log(String message) {
        logger.log("[" + System.currentTimeMillis() + "] " + message);  // ADD timestamp
    }
}

class LevelDecorator extends LoggerDecorator {
    String level;
    LevelDecorator(Logger logger, String level) { super(logger); this.level = level; }
    @Override
    public void log(String message) {
        logger.log("[" + level + "] " + message);  // ADD level prefix
    }
}

// Stack multiple decorators — all behaviors are CUMULATIVE
Logger logger = new ConsoleLogger();
logger = new TimestampDecorator(logger);  // adds timestamp
logger = new LevelDecorator(logger, "INFO");  // also adds level
logger.log("Application started");
// Output: [INFO] [1719000000000] Application started

// Key difference:
// Strategy: DataProcessor uses QuickSort OR MergeSort (mutually exclusive)
// Decorator: Logger uses Console + Timestamp + Level (all active, stacked)

// WITHOUT Factory — object creation mixed with business logic
class BadLogisticsService {
    public void send(String mode) {
        Logistics logistics;
        // Object creation and if-else INSIDE business logic — SRP violation + OCP violation
        if (mode.equals("Air")) {
            logistics = new Air();   // tight coupling
        } else if (mode.equals("Road")) {
            logistics = new Road();  // tight coupling
        } else {
