// FACTORY PATTERN — separate creation from usage

// Product interface
interface Logistics {
    void send();
}

// Concrete products
class Air implements Logistics {
    @Override public void send() { System.out.println("Sending by Air"); }
}

class Road implements Logistics {
    @Override public void send() { System.out.println("Sending by Road"); }
}

// Adding new type — zero changes to existing classes
class Sea implements Logistics {
    @Override public void send() { System.out.println("Sending by Sea"); }
}

// FACTORY — sole responsibility: create the right object
class LogisticsFactory {
    // Static factory method — no need to instantiate the factory itself
    public static Logistics getLogistics(String mode) {
        switch (mode) {
            case "Air":  return new Air();
            case "Road": return new Road();
            case "Sea":  return new Sea();   // added here only
            default: throw new IllegalArgumentException("Unknown mode: " + mode);
        }
    }
}

// BUSINESS LOGIC — no object creation, no if-else for types
class LogisticsService {
    public void send(String mode) {
        // Doesn't know or care how the Logistics object was created
        Logistics logistics = LogisticsFactory.getLogistics(mode);
        logistics.send();  // just uses it
    }
}

