// 1. EARLY LOADING (Eager) — thread-safe by design, but wastes memory if unused
class EagerSingleton {
    // Created when class is loaded — JVM guarantees this happens only once
    private static final EagerSingleton instance = new EagerSingleton();

    private EagerSingleton() {}  // private constructor — no one can call new

    public static EagerSingleton getInstance() {
        return instance;  // no synchronization needed — already created
    }
}

// 2. LAZY LOADING — saves memory, but NOT thread-safe without extra work
class UnsafeLazySingleton {
    private static UnsafeLazySingleton instance;  // null initially
    private UnsafeLazySingleton() {}

    public static UnsafeLazySingleton getInstance() {
        if (instance == null) {           // T1 sees null
            // OS context switch here!
            // T2 also sees null and creates instance
            instance = new UnsafeLazySingleton();  // T1 also creates!
        }                                 // Result: TWO instances — Singleton broken!
        return instance;
    }
}

// 3. SYNCHRONIZED METHOD — thread-safe but slow (locks on every call)
class SyncSingleton {
    private static SyncSingleton instance;
    private SyncSingleton() {}

    // Lock acquired on EVERY call — even after instance already exists!
    public static synchronized SyncSingleton getInstance() {
        if (instance == null) {
            instance = new SyncSingleton();
        }
        return instance;
    }
}

// 4. DOUBLE-CHECKED LOCKING — best of both worlds (PREFERRED)
class Singleton {
    // volatile: ensures ALL threads see fully constructed object
    // Without volatile: JVM can reorder constructor steps causing
    // another thread to see non-null but partially initialized object!
    private static volatile Singleton instance;

    private Singleton() {}

    public static Singleton getInstance() {
        if (instance == null) {              // First check — NO lock (fast path)
            synchronized (Singleton.class) { // Lock acquired only when null
                if (instance == null) {      // Second check — inside lock
                    // Recheck: another thread might have created it
                    // between our first check and acquiring the lock
                    instance = new Singleton();
                }
            }
        }
        return instance;  // Once created, NO locking ever again
    }
}

// Real-world example — Global Analytics Counter
class JudgeAnalytics {
    private static volatile JudgeAnalytics instance;
    private int runCount = 0;
    private int submitCount = 0;

    private JudgeAnalytics() {}

    public static JudgeAnalytics getInstance() {
        if (instance == null) {
            synchronized (JudgeAnalytics.class) {
                if (instance == null) instance = new JudgeAnalytics();
            }
        }
        return instance;
    }

    public synchronized void incrementRun()    { runCount++; }
    public synchronized void incrementSubmit() { submitCount++; }
    public int getRunCount()    { return runCount; }
    public int getSubmitCount() { return submitCount; }
}

// WHY volatile MATTERS — instruction reordering problem

// instance = new Singleton() is actually THREE steps:
// Step 1: Allocate memory → get address 0x7f4a
// Step 2: Initialize object → call constructor, set all fields
// Step 3: Assign address → instance = 0x7f4a

// JVM CAN reorder to: Step 1 → Step 3 → Step 2
// (assigns reference BEFORE constructor runs!)

// WITHOUT volatile — THE RACE:
class BrokenSingleton {
    private static BrokenSingleton instance;  // NOT volatile!
    private int importantValue;

    private BrokenSingleton() {
        importantValue = 42;  // constructor sets this
    }

    public static BrokenSingleton getInstance() {
        if (instance == null) {              // Thread B checks here
            synchronized (BrokenSingleton.class) {
                if (instance == null) {
                    instance = new BrokenSingleton();
                    // JVM might: allocate → ASSIGN TO INSTANCE → initialize
                    // Thread B can see non-null instance BEFORE constructor ran!
                }
            }
        }
        return instance;  // Thread B returns PARTIALLY CONSTRUCTED object!
    }
}

// Thread A timeline:             Thread B timeline:
// allocate memory
// ASSIGN instance = 0x7f4a  ←←← Thread B reads instance: NOT NULL!
//                                return instance (broken!)
//                                instance.importantValue → 0 (not 42!)
// run constructor (importantValue=42)  ← too late for Thread B

// WITH volatile — SAFE:
class SafeSingleton {
    private static volatile SafeSingleton instance;  // volatile!
    private int importantValue;

    private SafeSingleton() {
        importantValue = 42;
    }

    public static SafeSingleton getInstance() {
        if (instance == null) {
            synchronized (SafeSingleton.class) {
                if (instance == null) {
                    instance = new SafeSingleton();
                    // volatile guarantees:
                    // ALL writes before this line (constructor) are
                    // VISIBLE to ALL threads BEFORE they see non-null instance
                }
            }
        }
        return instance;  // guaranteed fully constructed
    }
}

// EXISTING system — PaymentGateway interface your system uses
interface PaymentGateway {
    void pay(String orderID, double amount);
}

// EXISTING implementation — works perfectly
class PayU implements PaymentGateway {
    @Override
    public void pay(String orderID, double amount) {
        System.out.println("PayU: Paid ₹" + amount + " for order " + orderID);
    }
}

// THIRD-PARTY library — RazorPay has completely different method name!
// Cannot modify this class (it's a library you don't own)
class RazorPayAPI {
    public void payment(String orderID, double amount) {  // different method name!
        System.out.println("RazorPay: Paid ₹" + amount + " for order " + orderID);
    }
}

// SERVICE — uses PaymentGateway interface
class PaymentService {
    private PaymentGateway paymentGateway;

    PaymentService(PaymentGateway paymentGateway) {
        this.paymentGateway = paymentGateway;
    }

    public void checkout(String orderID, double amount) {
        paymentGateway.pay(orderID, amount);  // only knows PaymentGateway
    }
}

// WITHOUT Adapter — BAD: must modify PaymentService to call RazorPay directly
// class PaymentService {
//     if (useRazorPay) razorPayAPI.payment(orderID, amount);  // OCP violation!
//     else payU.pay(orderID, amount);
// }

// ADAPTER — translates PaymentGateway.pay() → RazorPayAPI.payment()
class RazorPayAdapter implements PaymentGateway {  // looks like PaymentGateway to your system
    private RazorPayAPI razorPayAPI;

    RazorPayAdapter() {
        this.razorPayAPI = new RazorPayAPI();  // wraps the incompatible class
    }

    @Override
    public void pay(String orderID, double amount) {
        // Translates call to RazorPay's different API
        razorPayAPI.payment(orderID, amount);  // delegation with translation
    }
}

