public class Main {
    public static void main(String[] args) {
        // Original: use PayU
        PaymentService service1 = new PaymentService(new PayU());
        service1.checkout("ABC123", 1245.0);

        // New: use RazorPay through adapter — PaymentService code untouched!
        PaymentService service2 = new PaymentService(new RazorPayAdapter());
        service2.checkout("ABC124", 999.0);
    }
}

import java.util.*;

// WITHOUT Flyweight — each tree stores all data independently
class TreeWithoutFlyweight {
    private int x, y;              // unique per tree (extrinsic)
    private String name;           // SAME for all oaks — redundant!
    private String color;          // SAME for all oaks — redundant!
    private String texture;        // SAME for all oaks — redundant!

    TreeWithoutFlyweight(int x, int y, String name, String color, String texture) {
        this.x = x; this.y = y;
        this.name = name; this.color = color; this.texture = texture;
    }
}
// 1,000,000 Oak trees → 1,000,000 copies of "Oak", "Green", "Rough" — wasteful!

// WITH Flyweight Pattern

// FLYWEIGHT object — stores INTRINSIC state (shared, immutable)
class TreeType {
    private String name;    // intrinsic — same for all oaks
    private String color;   // intrinsic — same for all oaks
    private String texture; // intrinsic — same for all oaks

    TreeType(String name, String color, String texture) {
        this.name = name; this.color = color; this.texture = texture;
    }

    // Extrinsic state passed as parameter — not stored here
    public void draw(int x, int y) {
        System.out.println("Drawing " + name + " at (" + x + "," + y + ")");
    }
}

// Each Tree stores only EXTRINSIC state + reference to shared flyweight
class Tree {
    private int x, y;              // extrinsic — unique per tree
    private TreeType treeType;     // reference to SHARED flyweight

    Tree(int x, int y, TreeType treeType) {
        this.x = x; this.y = y;
        this.treeType = treeType;  // shared, NOT copied
    }

    public void draw() {
        treeType.draw(x, y);  // extrinsic state passed to flyweight
    }
}

// FLYWEIGHT FACTORY — ensures only one TreeType per unique combination
class TreeFactory {
    private static Map<String, TreeType> cache = new HashMap<>();

    public static TreeType getTreeType(String name, String color, String texture) {
        String key = name + "-" + color + "-" + texture;
        if (!cache.containsKey(key)) {
            // Create only if not already exists
            cache.put(key, new TreeType(name, color, texture));
            System.out.println("Created new TreeType: " + key);
        }
        return cache.get(key);  // return SHARED instance
    }
}

// Usage:
public class Main {
    public static void main(String[] args) {
        List<Tree> forest = new ArrayList<>();

        // 1,000,000 trees — only ONE TreeType object created!
        for (int i = 0; i < 1_000_000; i++) {
            TreeType oakType = TreeFactory.getTreeType("Oak", "Green", "Rough");
            // "Created new TreeType: Oak-Green-Rough" printed only ONCE
            forest.add(new Tree(i, i * 2, oakType));
        }

        // Memory:
        // Without Flyweight: 1,000,000 × (name + color + texture + x + y)
        // With Flyweight:    1 × (name + color + texture) + 1,000,000 × (x + y + reference)
        System.out.println("Forest size: " + forest.size());
        System.out.println("Unique tree types: " + TreeFactory.cache.size());  // 1!
    }
}

// ADAPTER — changes interface (incompatible → compatible)
interface ModernLogger { void log(String level, String msg); }
class LegacyLogger { void write(String msg) { System.out.println(msg); } }  // old API

class LoggerAdapter implements ModernLogger {
    private LegacyLogger legacy = new LegacyLogger();
    @Override
    public void log(String level, String msg) {
        legacy.write("[" + level + "] " + msg);  // translate new interface to old
    }
}

// DECORATOR — same interface, adds behavior cumulatively
interface DataSource {
    void writeData(String data);
    String readData();
}

class FileDataSource implements DataSource {
    private String data;
    public void writeData(String data) { this.data = data; }
    public String readData() { return data; }
}

class EncryptionDecorator implements DataSource {
    private DataSource wrapped;
    EncryptionDecorator(DataSource source) { this.wrapped = source; }
    public void writeData(String data) { wrapped.writeData(encrypt(data)); }  // add encrypt
    public String readData() { return decrypt(wrapped.readData()); }           // add decrypt
    private String encrypt(String s) { return "[ENC]" + s; }
    private String decrypt(String s) { return s.replace("[ENC]", ""); }
}

// PROXY — same interface, controls access
interface ExpensiveService {
    String getData();
}

class RealExpensiveService implements ExpensiveService {
    RealExpensiveService() {
        System.out.println("Expensive initialization...");  // slow constructor
    }
    @Override public String getData() { return "Real data"; }
}

// VIRTUAL PROXY — delays creation until first access
class LazyProxy implements ExpensiveService {
    private RealExpensiveService real = null;  // not created yet!

    @Override
    public String getData() {
        if (real == null) {
            real = new RealExpensiveService();  // create only when first needed
        }
        return real.getData();
    }
}

// PROTECTION PROXY — adds authorization
class ProtectionProxy implements ExpensiveService {
    private RealExpensiveService real = new RealExpensiveService();
    private String userRole;

    ProtectionProxy(String userRole) { this.userRole = userRole; }

    @Override
    public String getData() {
        if (!userRole.equals("ADMIN")) {
            throw new SecurityException("Access denied for role: " + userRole);
        }
        return real.getData();
    }
}

// Summary:
// Adapter  → changes interface (A→B translation)
// Decorator → adds behavior (same interface, cumulative)
// Proxy    → controls access (same interface, interception)

// PROBLEM: Telescoping constructors — unreadable and error-prone
class BadUser {
    BadUser(String name, String email) { }
    BadUser(String name, String email, int age) { }
    BadUser(String name, String email, int age, String phone) { }
    BadUser(String name, String email, int age, String phone, String address) { }
    // Calling: new BadUser("Harsh", "h@e.com", 0, null, "CA")  — which param is which?
}

// BUILDER PATTERN — readable, validates, prevents invalid state
class User {
    // Required fields
    private final String name;
    private final String email;

    // Optional fields
    private final int age;
    private final String phone;
    private final String address;
    private final String gender;

    // Private constructor — only Builder can create User
    private User(Builder builder) {
        this.name    = builder.name;
        this.email   = builder.email;
        this.age     = builder.age;
        this.phone   = builder.phone;
        this.address = builder.address;
        this.gender  = builder.gender;
    }

    // STATIC INNER BUILDER CLASS
    public static class Builder {
        // Required — must be set
        private final String name;
        private final String email;

        // Optional — have defaults
        private int age = 0;
        private String phone   = "";
        private String address = "";
        private String gender  = "";

        // Required fields in Builder constructor
        public Builder(String name, String email) {
            if (name == null || name.isEmpty())
                throw new IllegalArgumentException("Name is required");
            if (email == null || !email.contains("@"))
                throw new IllegalArgumentException("Valid email required");
            this.name  = name;
            this.email = email;
        }

        // Optional setters — each returns 'this' for method chaining
        public Builder age(int age) {
            if (age < 0 || age > 150) throw new IllegalArgumentException("Invalid age");
            this.age = age;
            return this;
        }

        public Builder phone(String phone)     { this.phone = phone;     return this; }
        public Builder address(String address) { this.address = address; return this; }
        public Builder gender(String gender)   { this.gender = gender;   return this; }

        // Build — creates the final immutable User
        public User build() {
            return new User(this);
        }
    }

    @Override
    public String toString() {
        return "User{name='" + name + "', email='" + email +
               "', age=" + age + ", phone='" + phone + "'}";
    }
}

// Usage — readable, self-documenting fluent API
User user = new User.Builder("Harsh", "harsh@example.com")
    .age(25)
    .phone("+1-408-555-0100")
    .address("San Jose, CA")
    .gender("Male")
    .build();

System.out.println(user);
// Clear which value is which — no confusion about parameter order

// PATTERN RECOGNITION CHEAT SHEET:

// Problem: "We need exactly one database connection pool across the app"
// → SINGLETON (one instance, globally shared)

// Problem: "Create shipping by Air, Road, or Sea based on user choice"
// → FACTORY (create objects based on type input)

// Problem: "We have Light and Dark themes — buttons, checkboxes, textfields must all match"
// → ABSTRACT FACTORY (create families of related objects consistently)

// Problem: "Uber needs Nearest, Priority, Airport ride matching — add new types easily"
// → STRATEGY (interchangeable algorithms, replace if-else)

// Problem: "When stock price changes, update charts, alerts, and dashboards"
// → OBSERVER (one changes, many need notification)

// Problem: "Add timestamps, encryption, compression to logger in any combination"
// → DECORATOR (cumulative optional behavior, same interface)

// Problem: "Our system uses PaymentGateway but new provider has different API"
// → ADAPTER (translate incompatible interface)

// Problem: "Loading this object is expensive — delay until first use"
// → PROXY (Virtual Proxy for lazy initialization)

// Problem: "User object has 10 fields, 7 optional — constructor calls are unreadable"
// → BUILDER (step-by-step construction, fluent API)

// Interview approach when asked about any design problem:
// Step 1: Identify the category (Creational/Structural/Behavioral)
// Step 2: Name the pattern
// Step 3: State the problem it solves
// Step 4: Name the components (Interface/Concrete/Context)
// Step 5: Write the code
// Step 6: Mention which SOLID principle it satisfies

// Example answer:
// Q: "Design a notification system for a news app"
// A: "I'd use Observer Pattern (Behavioral). Problem: when an article is
//     published, multiple subscribers (email, app, SMS) need notification.
//     Components: Subscriber interface with update(), concrete EmailSubscriber
//     and AppSubscriber, NewsChannel subject that maintains subscriber list
//     and calls notifyAll() on new publication. This follows OCP — adding
//     WhatsApp notifications requires only a new subscriber class."
